PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?propriedade ?label_pt ?label_en ?dominio ?range
WHERE {
  ?propriedade rdfs:domain geo:poco ;
               rdfs:range geo:bloco ;
               rdfs:label ?label_pt ;
               rdfs:label ?label_en .
  FILTER(LANG(?label_pt) = "pt")
  FILTER(LANG(?label_en) = "en")
}

PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?prop ?label_pt ?range
WHERE {
  ?prop a owl:ObjectProperty ;
        rdfs:domain geo:poco ;
        rdfs:label ?label_pt .
  OPTIONAL { ?prop rdfs:range ?range . }
  FILTER(LANG(?label_pt) = "pt")
}
ORDER BY ?prop

