PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?entityType (COUNT(?classe) AS ?total)
WHERE {
  ?classe a owl:Class ;
          geo:entityType ?entityType .
}
GROUP BY ?entityType
ORDER BY DESC(?total)

