PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?prop ?label_pt ?dominio ?range
WHERE {
  ?prop a owl:ObjectProperty ;
        rdfs:domain ?dominio ;
        rdfs:range ?range ;
        rdfs:label ?label_pt .
  ?dominio geo:entityType "geological" .
  ?range geo:entityType "geological" .
  FILTER(LANG(?label_pt) = "pt")
}

PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
SELECT ?label ?definition ?altLabel
WHERE {
  geo:regime-contratual skos:prefLabel ?label ;
                        skos:definition ?definition .
  OPTIONAL { geo:regime-contratual skos:altLabel ?altLabel . }
  FILTER(LANG(?label) = "pt")
  FILTER(LANG(?definition) = "pt")
  FILTER(!BOUND(?altLabel) || LANG(?altLabel) = "pt")
}

PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?prop ?label_pt ?dominio
WHERE {
  ?prop a owl:ObjectProperty ;
        rdfs:range geo:bacia-sedimentar ;
        rdfs:label ?label_pt .
  OPTIONAL { ?prop rdfs:domain ?dominio . }
  FILTER(LANG(?label_pt) = "pt")
}

PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
SELECT ?classe ?label ?example
WHERE {
  ?classe skos:example ?example ;
          skos:prefLabel ?label .
  FILTER(CONTAINS(?example, "Santos") || CONTAINS(?example, "Campos"))
  FILTER(LANG(?label) = "pt")
}

PREFIX geo: <https://geolytics.petrobras.com.br/dict/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?prop ?label_pt ?label_en
WHERE {
  ?prop a owl:ObjectProperty .
  FILTER(STRSTARTS(STR(?prop), STR(geo:)))
  OPTIONAL { ?prop rdfs:label ?label_pt . FILTER(LANG(?label_pt) = "pt") }
  OPTIONAL { ?prop rdfs:label ?label_en . FILTER(LANG(?label_en) = "en") }
}
ORDER BY ?prop

